mapper.select:
WITH filtered AS ( SELECT id, art_code, stock_code, stock_name, title, tag, link, pub_date, create_time, event_type, signal_side, signal_score, cluster_key FROM a_stock_rss WHERE pub_date >= #{startTime} AND pub_date <= #{endTime}
AND (title IS NULL OR title NOT LIKE CONCAT('%', #{kw}, '%'))
), ranked AS ( SELECT filtered.*, COUNT(*) OVER (PARTITION BY stock_code) AS frequency, ROW_NUMBER() OVER (PARTITION BY stock_code ORDER BY pub_date DESC, id DESC) AS rn FROM filtered ) SELECT id, art_code, stock_code, stock_name, title, tag, link, pub_date, create_time, event_type, signal_side, signal_score, cluster_key, frequency FROM ranked WHERE rn = 1 AND frequency >= #{threshold} ORDER BY frequency DESC, pub_date DESC LIMIT #{limit}

SELECT id, art_code, stock_code, stock_name, title, tag, link, pub_date, create_time, event_type, signal_side, signal_score, cluster_key FROM a_stock_rss WHERE stock_code IN
#{stockCode}
AND pub_date >= #{startTime} AND pub_date <= #{endTime}
AND (title IS NULL OR title NOT LIKE CONCAT('%', #{kw}, '%'))
ORDER BY stock_code ASC, pub_date DESC
